final class PromoManager {
    static let shared = PromoManager()

    struct PromoApplication {
        let code: String
        let discount: Int
        let url: URL
    }

    private(set) var appliedPromos: [PromoApplication] = []

    func handleUniversalLink(_ url: URL) -> Bool {
        guard url.scheme?.lowercased() == "https",
              url.host?.lowercased() == "myapp.com",
              url.path == "/promo",
              let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return false
        }

        let items = components.queryItems ?? []
        guard let code = items.first(where: { $0.name == "code" })?.value,
              let discountString = items.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString),
              !code.isEmpty else {
            return false
        }

        applyPromo(code: code, discount: discount, url: url)
        return true
    }

    func applyPromo(code: String, discount: Int, url: URL) {
        let promo = PromoApplication(code: code, discount: discount, url: url)
        appliedPromos.append(promo)
        UserAccountStore.shared.applyPromo(code: code, discount: discount)
        NotificationCenter.default.post(name: .promoApplied, object: promo)
    }
}

